import{_ as l,o as a,c as e,a3 as t}from"./chunks/framework.gsMzR_Kb.js";const m=JSON.parse('{"title":"六十四卦目录","description":"先建立六十四卦的目录感与分组感，再逐步进入逐卦阅读。","frontmatter":{"title":"六十四卦目录","description":"先建立六十四卦的目录感与分组感，再逐步进入逐卦阅读。"},"headers":[],"relativePath":"yijing/hexagrams/index.md","filePath":"yijing/hexagrams/index.md","lastUpdated":1777132262000}'),o={name:"yijing/hexagrams/index.md"};function r(d,i,n,h,c,s){return a(),e("div",null,[...i[0]||(i[0]=[t('<h1 id="六十四卦目录" tabindex="-1">六十四卦目录 <a class="header-anchor" href="#六十四卦目录" aria-label="Permalink to &quot;六十四卦目录&quot;">​</a></h1><p>这里当前先做“目录层”，不急着一次性生成 64 篇详解。</p><p>更稳的方式仍然是分三步：</p><ol><li>先建立目录页</li><li>再建立统一模板</li><li>学到哪个卦，再补哪个卦</li></ol><h2 id="为什么目录层很重要" tabindex="-1">为什么目录层很重要 <a class="header-anchor" href="#为什么目录层很重要" aria-label="Permalink to &quot;为什么目录层很重要&quot;">​</a></h2><p>很多人读《易》时的困难，不是单卦太难，而是没有整体感。</p><p>目录页的作用就是先让你知道：</p><ul><li>六十四卦不是散乱堆在一起</li><li>它们有次序，也能分组</li><li>你后面逐卦学习时，随时能回到总图里定位</li></ul><h2 id="当前建议结构" tabindex="-1">当前建议结构 <a class="header-anchor" href="#当前建议结构" aria-label="Permalink to &quot;当前建议结构&quot;">​</a></h2><ul><li><code>index.md</code>：六十四卦总入口</li><li><code>_template.md</code>：单卦记录模板</li><li><code>qian.md</code>、<code>kun.md</code> 等：逐步落内容</li></ul><h2 id="后续可记录字段" tabindex="-1">后续可记录字段 <a class="header-anchor" href="#后续可记录字段" aria-label="Permalink to &quot;后续可记录字段&quot;">​</a></h2><ul><li>卦序</li><li>卦名</li><li>上下卦</li><li>卦辞</li><li>核心关键词</li><li>三问解读</li><li>关联专题</li><li>参考来源</li></ul><h2 id="六十四卦目录-按次序" tabindex="-1">六十四卦目录（按次序） <a class="header-anchor" href="#六十四卦目录-按次序" aria-label="Permalink to &quot;六十四卦目录（按次序）&quot;">​</a></h2><h3 id="上经" tabindex="-1">上经 <a class="header-anchor" href="#上经" aria-label="Permalink to &quot;上经&quot;">​</a></h3><ol><li>乾</li><li>坤</li><li>屯</li><li>蒙</li><li>需</li><li>讼</li><li>师</li><li>比</li><li>小畜</li><li>履</li><li>泰</li><li>否</li><li>同人</li><li>大有</li><li>谦</li><li>豫</li><li>随</li><li>蛊</li><li>临</li><li>观</li><li>噬嗑</li><li>贲</li><li>剥</li><li>复</li><li>无妄</li><li>大畜</li><li>颐</li><li>大过</li><li>坎</li><li>离</li></ol><h3 id="下经" tabindex="-1">下经 <a class="header-anchor" href="#下经" aria-label="Permalink to &quot;下经&quot;">​</a></h3><ol start="31"><li>咸</li><li>恒</li><li>遯</li><li>大壮</li><li>晋</li><li>明夷</li><li>家人</li><li>睽</li><li>蹇</li><li>解</li><li>损</li><li>益</li><li>夬</li><li>姤</li><li>萃</li><li>升</li><li>困</li><li>井</li><li>革</li><li>鼎</li><li>震</li><li>艮</li><li>渐</li><li>归妹</li><li>丰</li><li>旅</li><li>巽</li><li>兑</li><li>涣</li><li>节</li><li>中孚</li><li>小过</li><li>既济</li><li>未济</li></ol><h2 id="初学时可以先怎么用这页" tabindex="-1">初学时可以先怎么用这页 <a class="header-anchor" href="#初学时可以先怎么用这页" aria-label="Permalink to &quot;初学时可以先怎么用这页&quot;">​</a></h2><ul><li>先把目录看熟，不急着背解释</li><li>每读到一个卦，就回到这里给自己定位</li><li>遇到反复出现的词，再回到 <a href="/Dao/yijing/basics/core-concepts">核心概念</a></li></ul><h2 id="后续建议补法" tabindex="-1">后续建议补法 <a class="header-anchor" href="#后续建议补法" aria-label="Permalink to &quot;后续建议补法&quot;">​</a></h2><ul><li>先补乾、坤、屯、蒙等起手卦</li><li>每补一卦，至少补“卦名、卦辞、关键词、三问”</li><li>解读层先留空也没关系，先把原典入口与结构建起来</li></ul>',21)])])}const p=l(o,[["render",r]]);export{m as __pageData,p as default};
